#include <stdio.h>
#include <stdlib.h>

int *parent;
int find_set(int x){
    if(parent[x]==x) return x;
    return parent[x]=find_set(parent[x]);
}
void union_set(int x,int y){
    parent[x]=y; // y is already a representative (find_set called before)
}
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int maxSize = 2*N + 5;
        parent = (int*)malloc(maxSize*sizeof(int));
        for(int i=0;i<maxSize;i++) parent[i]=i;
        int *ans = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++){
            int a; scanf("%d",&a);
            int seat = find_set(a);
            ans[i]=seat;
            union_set(seat, find_set(seat+1));
        }
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(parent);
        free(ans);
    }
    return 0;
}

