#include <bits/stdc++.h>
using namespace std;

struct DSU{
    vector<int> p;
    DSU(int n){p.resize(n); iota(p.begin(), p.end(), 0);}    
    int find(int x){return p[x]==x?x:p[x]=find(p[x]);}
    void occupy(int x){p[x]=find(x+1);} // mark seat x as taken
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        DSU dsu(2*N+5);
        vector<int> ans(N);
        for(int i=0;i<N;i++){
            int a; cin>>a;
            int seat = dsu.find(a);
            ans[i]=seat;
            dsu.occupy(seat);
        }
        for(int i=0;i<N;i++){
            if(i) cout<<' ';
            cout<<ans[i];
        }
        cout<<'\n';
    }
    return 0;
}

