const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const maxSize = 2 * N + 5;
  const parent = new Int32Array(maxSize);
  for (let i = 0; i < maxSize; i++) parent[i] = i;
  const find = (x) => {
    let root = x;
    while (parent[root] !== root) root = parent[root];
    // path compression
    while (parent[x] !== x) {
      const nxt = parent[x];
      parent[x] = root;
      x = nxt;
    }
    return root;
  };
  const ans = [];
  for (let i = 0; i < N; i++) {
    const a = Number(input[idx++]);
    const seat = find(a);
    ans.push(seat);
    parent[seat] = find(seat + 1); // occupy seat
  }
  output.push(ans.join(' '));
}
